dp就是把所有可能性，encode成index在matrix上記錄，在求解時利用index去取得答案

Sol
// 0 is 沒初始化，1是match，-1是mismatchint dp[1000][1000];class Solution &#123;public:    void initDP() &#123;        memset(dp, 0, sizeof(dp));    &#125;    bool equalChar(char a,char b) &#123;        return b == '.' || a == b;    &#125;    bool restAsterisk(int j,string&amp; p) &#123;        for(;j &gt;=0 &amp;&amp; p[j]=='*';j-=2);        return j &lt; 0;    &#125;    // i : S目前比對到哪    // j : P目前比對到哪    int f(int i,int j,string &amp;S,string &amp;P) &#123;        if(j &lt; 0 &amp;&amp; i &lt; 0) // 都沒得比了就是match             return 1;        else if(j &lt; 0) // pattern沒得比，S還有剩，mismatch            return -1;        else if(i &lt; 0) // pattern還有剩，S沒得比，看剩下的是不是都是星號            return restAsterisk(j,P) ? 1 : -1;        else if(dp[i][j] == 0) // 在dp上沒有被算過            if(P[j] == '*') &#123; // P是星號                // 星號就要列舉沒match到所有能match的case                dp[i][j] = f(i,j-2,S,P); // &lt;c&gt;* doesnt match anything                for(int k=i;k&gt;=0 &amp;&amp; equalChar(S[k],P[j-1]);k--)                    if(f(k-1,j-2,S,P)&gt;0)                        dp[i][j] = f(k-1,j-2,S,P);                            &#125; else // P是字元                dp[i][j] = equalChar(S[i],P[j]) ? f(i-1,j-1,S,P) : false;        else;        return dp[i][j];    &#125;    bool isMatch(string s, string p) &#123;        initDP();        return f(s.size()-1,p.size()-1,s,p) &gt; 0;    &#125;&#125;;
