html終於可以抽象成一個tag了

template &amp;&amp; shadow DOM

shadow DOM: 可以長出自己的DOM tree的hook點，這樣就可以把整坨html藏起來
template: 獨立於document之外的DOM tree

&lt;template id="userCardTemplate"&gt;  &lt;style&gt;...&lt;/style&gt;  &lt;img class="image"&gt;  &lt;div class="container"&gt;    &lt;p class="name"&gt;&lt;/p&gt;    &lt;p class="email"&gt;&lt;/p&gt;    &lt;button class="button"&gt;Follow John&lt;/button&gt;  &lt;/div&gt;&lt;/template&gt;
class UserCard extends HTMLElement &#123;  constructor() &#123;    super();    var shadow = this.attachShadow( &#123; mode: 'closed' &#125; ); // shadow DOM 隔開 宿主網頁    var templateElem = document.getElementById('userCardTemplate');    var content = templateElem.content.cloneNode(true); // clone template    content.querySelector('img').setAttribute('src', this.getAttribute('image')); // 從attr拿資料，但有更好的方法    content.querySelector('.container&gt;.name').innerText = this.getAttribute('name');    content.querySelector('.container&gt;.email').innerText = this.getAttribute('email');    shadow.appendChild(content);  &#125;&#125;window.customElements.define('user-card', UserCard);
&lt;user-card name="name" email="123@123.com" src="123.jpg"&gt;&lt;/user-card&gt;
