#include &lt;random&gt;class RandomizedSet &#123;private:    list&lt;int&gt; l;    unordered_map&lt;int, list&lt;int&gt;::iterator&gt; m;    std::mt19937_64 rng;public:    /** Initialize your data structure here. */    RandomizedSet() &#123;        std::random_device dev;        std::mt19937_64 rng2(dev());        rng = rng2;    &#125;        /** Inserts a value to the set. Returns true if the set did not already contain the specified element. */    bool insert(int val) &#123;        bool ret = 0;        if (m.find(val) == m.end()) &#123;            l.push_front(val);            m[val] = l.begin();            ret = 1;        &#125;        return ret;    &#125;        /** Removes a value from the set. Returns true if the set contained the specified element. */    bool remove(int val) &#123;        bool ret = 0;        if (m.find(val) != m.end()) &#123;            l.erase(m[val]);            m.erase(val);            ret = 1;        &#125;        return ret;    &#125;        /** Get a random element from the set. */    int getRandom() &#123;        std::uniform_int_distribution&lt;size_t&gt; idDist(0, m.size() - 1);        auto item = m.begin();        std::advance( item, idDist(rng) );        return item-&gt;first;    &#125;&#125;;
